import{_ as e,o as s,c as n,a0 as t}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"What is BlockGuard?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-blockguard.md","filePath":"guide/what-is-blockguard.md"}'),o={name:"guide/what-is-blockguard.md"};function r(i,a,l,d,p,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="what-is-blockguard" tabindex="-1">What is BlockGuard? <a class="header-anchor" href="#what-is-blockguard" aria-label="Permalink to &quot;What is BlockGuard?&quot;">​</a></h1><p>Every time you open a website, click a link, or use any app that connects to the internet, your device performs a <strong>DNS lookup</strong> — it asks a DNS server to translate a domain name (like <code>ads.google.com</code>) into an IP address.</p><p>BlockGuard sits between your device and the internet as a <strong>local DNS server</strong>. It intercepts every DNS query and checks it against 312,000+ known ad, tracker, and malware domains:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐         ┌──────────────────┐         ┌──────────────┐</span></span>
<span class="line"><span>│  Your Device │──DNS──▶ │   BlockGuard     │──DNS──▶ │  Internet    │</span></span>
<span class="line"><span>│  (Browser,   │  Query  │   (127.0.0.1)    │  Query  │  (1.1.1.1)   │</span></span>
<span class="line"><span>│   Apps,      │         │                  │         │              │</span></span>
<span class="line"><span>│   Games)     │◀─Reply──│  ✅ Clean domain │◀─Reply──│              │</span></span>
<span class="line"><span>│              │         │  → Forward       │         │              │</span></span>
<span class="line"><span>│              │◀─Block──│  ❌ Ad/Tracker   │         │              │</span></span>
<span class="line"><span>│              │         │  → Return NXDOMAIN│        │              │</span></span>
<span class="line"><span>└──────────────┘         └──────────────────┘         └──────────────┘</span></span></code></pre></div><h2 id="key-advantages-over-browser-extensions" tabindex="-1">Key Advantages over Browser Extensions <a class="header-anchor" href="#key-advantages-over-browser-extensions" aria-label="Permalink to &quot;Key Advantages over Browser Extensions&quot;">​</a></h2><ul><li><strong>Blocks ads in ALL applications</strong> — Not just browsers, but games, Spotify, Discord, and desktop apps.</li><li><strong>Blocks tracking &amp; telemetry</strong> — Stops background system analytics from spying on your usage.</li><li><strong>Saves bandwidth &amp; battery</strong> — Ads are blocked <em>before</em> they are downloaded, saving data and reducing page rendering CPU workload.</li><li><strong>Un-bypassable</strong> — Websites that detect and block traditional browser extensions often cannot detect DNS-level blocking.</li><li><strong>System-wide coverage</strong> — Protects your entire computer with a single running command.</li></ul>`,6)])])}const k=e(o,[["render",r]]);export{u as __pageData,k as default};
